import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import './Navbar.css';

function Navbar() {
    const location = useLocation();
    const token = localStorage.getItem('token');
    const [quickBody, setQuickBody] = useState('');
    const [quickSubject, setQuickSubject] = useState('HR Team');
    const [formTitle, setFormTitle] = useState('');
    const [formLoading, setFormLoading] = useState(false);

    if (!token) return null;

    const isActive = (path) => location.pathname === path ? 'active' : '';

    const handleQuickMail = (e) => {
        e.preventDefault();
        if (!quickBody.trim()) return;
        const mailto = `mailto:nagumeenaudayappan.23aid@kongu.edu?subject=${encodeURIComponent(quickSubject)}&body=${encodeURIComponent(quickBody)}`;
        window.location.href = mailto;
    };

    const handleFormMail = (e) => {
        e.preventDefault();
        if (!formTitle.trim()) return;
        setFormLoading(true);
        setTimeout(() => {
            const mailto = `mailto:nagumeenaudayappan.23aid@kongu.edu?subject=${encodeURIComponent('Software')}&body=${encodeURIComponent(formTitle)}`;
            window.location.href = mailto;
            setFormLoading(false);
        }, 3000);
    };

    return (
        <nav className="global-navbar">
            <div className="nav-container">
                <Link to="/" className="nav-logo">PowerGrid AI</Link>
                <div className="nav-links">
                    <Link to="/" className={`nav-link ${isActive('/')}`}>Home</Link>
                    <Link to="/my-tickets" className={`nav-link ${isActive('/my-tickets')}`}>My Tickets</Link>
                    <Link to="/new-ticket" className={`nav-link ${isActive('/new-ticket')}`}>New Ticket</Link>
                    <Link to="/analytics" className={`nav-link ${isActive('/analytics')}`}>Analytics</Link>
                    <Link to="/sla-tracker" className={`nav-link ${isActive('/sla-tracker')}`}>SLA Monitor</Link>
                    <Link to="/knowledge-base" className={`nav-link ${isActive('/knowledge-base')}`}>Knowledge Base</Link>
                    <Link to="/chatbot" className={`nav-link ${isActive('/chatbot')}`}>AI Assistant</Link>
                    <Link to="/excel-upload" className={`nav-link ${isActive('/excel-upload')}`}>Excel Upload</Link>
                </div>
                <div className="nav-actions">
                    <button
                        onClick={() => {
                            localStorage.removeItem('token');
                            window.location.href = '/login';
                        }}
                        className="logout-btn"
                    >
                        Sign Out
                    </button>
                </div>
            </div>

            <div className="nav-quick-mail">
                <form className="nav-quick-form" onSubmit={handleQuickMail}>
                    <label className="nav-quick-label">Quick mail to HR/General</label>
                    <select
                        value={quickSubject}
                        onChange={(e) => setQuickSubject(e.target.value)}
                        className="nav-quick-select"
                    >
                        <option>HR Team</option>
                        <option>General Team</option>
                    </select>
                    <input
                        type="text"
                        placeholder="Write a short note..."
                        value={quickBody}
                        onChange={(e) => setQuickBody(e.target.value)}
                        className="nav-quick-input"
                    />
                    <button type="submit" className="nav-quick-send">Send</button>
                </form>
            </div>

            <div className="nav-form-mail">
                <form className="nav-form" onSubmit={handleFormMail}>
                    <label className="nav-quick-label">Form · send to Software team</label>
                    <input
                        type="text"
                        placeholder="Issue title..."
                        value={formTitle}
                        onChange={(e) => setFormTitle(e.target.value)}
                        className="nav-form-input"
                    />
                    <button type="submit" className="nav-form-send" disabled={formLoading}>
                        {formLoading ? 'Analysing...' : 'Submit'}
                    </button>
                </form>
            </div>
        </nav>
    );
}

export default Navbar;
